// jkanban 的 +esm 在严格模块中把 jKanban 写到 undefined this；隔离 iframe 内加载含 dragula 的经典构建
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/jkanban@1.3.1/dist/jkanban.min.css'; document.head.appendChild(css);
const el = document.getElementById('kanban'); el.style.minHeight = '180px'; el.textContent = 'Loading board…';
const previousJKanban = globalThis.jKanban;
const script = Object.assign(document.createElement('script'), { src: 'https://cdn.jsdelivr.net/npm/jkanban@1.3.1/dist/jkanban.min.js' });
await new Promise((resolve, reject) => { script.onload = resolve; script.onerror = reject; document.head.appendChild(script); });
const jKanban = globalThis.jKanban; el.replaceChildren();
const kanban = new jKanban({ element: '#kanban', boards: data.boards, gutter: data.gutter ?? '15px', widthBoard: data.widthBoard ?? '250px', dragItems: data.dragItems ?? true, dragBoards: data.dragBoards ?? true, responsivePercentage: data.responsivePercentage ?? false });
if (previousJKanban === undefined) delete globalThis.jKanban; else globalThis.jKanban = previousJKanban;

